// The age/sex FITNESS-NORM dataset, loaded onto the curated-dataset framework (issue
// #860 Track B). Copies the mets.ts / icd10-common.ts shape: import the envelope JSON
// (generated by scripts/gen-fitness-norms.ts), validate it once with loadDataset(), and
// expose the marker ENTRIES + a name→MarkerNorms map the pure lookup consumes. Identity
// is the canonical marker `name` (nameStrategy) — one entry per marker. The registry
// lists this for the linter; lib/fitness-norms.ts is the pure percentile / fitness-age
// lookup over these entries. Pure — no DB, no network.

import rawNorms from "./data/fitness-norms.json";
import { loadDataset } from "./loader";
import { nameStrategy } from "./matcher";
import type {
  FitnessNormEntry,
  MarkerNorms,
} from "@/scripts/gen-fitness-norms";

export type {
  FitnessNormEntry,
  MarkerNorms,
  SexNorms,
  NormBand,
  Direction,
} from "@/scripts/gen-fitness-norms";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const fitnessNormsDataset = loadDataset<FitnessNormEntry>(rawNorms);

// Identity strategy: the canonical marker `name` (case-folded). For the linter/harness —
// each entry carries a unique name, so identity resolves and an unknown name refuses.
export const fitnessNormNameStrategy = nameStrategy;

// The marker entries (curated order) the pure lookup consumes.
export const FITNESS_NORM_ENTRIES: FitnessNormEntry[] =
  fitnessNormsDataset.entries;

// A name→MarkerNorms map rebuilt from the entries, keyed by the EXACT canonical marker
// name (byte-for-byte, so the pure lookup's `MARKERS[name]` and Object.keys behave
// exactly as they did over the old `{ markers }` map). One source of truth for the shape.
export const FITNESS_NORM_MARKERS_MAP: Record<string, MarkerNorms> =
  Object.fromEntries(
    FITNESS_NORM_ENTRIES.map((e) => {
      const { name, ...norms } = e;
      return [name, norms as MarkerNorms];
    })
  );
